import { TextInput } from "@/components/ra-wrappers/text-input";
import { ReferenceInput } from "@/components/ra-wrappers/reference-input";
import { SelectInput } from "@/components/ra-wrappers/select-input";
import {
  CollapsibleSection,
  CompactFormRow,
  FormFieldWrapper,
  FormSectionWithProgress,
} from "@/components/ra-wrappers/form";
import { Avatar } from "./Avatar";
import { ContactAdditionalDetails } from "./ContactAdditionalDetails";
import { EmailArrayField, PhoneArrayField } from "@/components/domain/forms";
import { OrganizationPicker } from "./OrganizationPicker";
import { useFormContext } from "react-hook-form";
import { saleOptionRenderer } from "../utils/saleOptionRenderer";
import * as React from "react";
import { ucFirst, extractEmailLocalPart } from "@/atomic-crm/utils";

interface ContactCompactFormProps {
  disabled?: boolean;
}

export const ContactCompactForm = ({ disabled = false }: ContactCompactFormProps) => {
  const { setValue, getValues } = useFormContext();

  const handleEmailChange = (email: string) => {
    const { first_name, last_name } = getValues();
    if (first_name || last_name || !email) return;
    const localPart = extractEmailLocalPart(email);
    if (!localPart) return;
    const [first, last] = localPart.split(".");
    if (!first) return;
    setValue("first_name", ucFirst(first));
    setValue("last_name", last ? ucFirst(last) : "");
  };

  const handleEmailPaste: React.ClipboardEventHandler<HTMLTextAreaElement | HTMLInputElement> = (
    e
  ) => {
    const email = e.clipboardData?.getData("text/plain");
    handleEmailChange(email);
  };

  const handleEmailBlur = (e: React.FocusEvent<HTMLTextAreaElement | HTMLInputElement>) => {
    const email = e.target.value;
    handleEmailChange(email);
  };

  return (
    <div className="space-y-6">
      <FormSectionWithProgress
        id="name-section"
        title="Contact Profile"
        requiredFields={["first_name", "last_name"]}
      >
        <CompactFormRow columns="md:grid-cols-[1fr_1fr_auto]" alignItems="start">
          <div>
            <FormFieldWrapper name="first_name" isRequired>
              <TextInput
                source="first_name"
                label="First Name"
                helperText="First name is required"
                autoComplete="given-name"
                disabled={disabled}
              />
            </FormFieldWrapper>
          </div>
          <div>
            <FormFieldWrapper name="last_name" isRequired>
              <TextInput
                source="last_name"
                label="Last Name"
                helperText="Last name is required"
                autoComplete="family-name"
                disabled={disabled}
              />
            </FormFieldWrapper>
          </div>
          <div className="pt-6">
            <Avatar />
          </div>
        </CompactFormRow>
      </FormSectionWithProgress>

      <FormSectionWithProgress
        id="organization-section"
        title="Account Details"
        requiredFields={["organization_id", "sales_id"]}
      >
        {/* Organization - full width row */}
        <div>
          <FormFieldWrapper name="organization_id" isRequired countDefaultAsFilled>
            <OrganizationPicker
              label="Organization"
              helperText="Organization is required"
              disabled={disabled}
            />
          </FormFieldWrapper>
        </div>

        {/* Account Manager - full width row */}
        <div>
          <FormFieldWrapper name="sales_id" isRequired countDefaultAsFilled>
            <ReferenceInput
              reference="sales"
              source="sales_id"
              sort={{ field: "last_name", order: "ASC" }}
              filter={{
                "disabled@neq": true,
                "user_id@not.is": null,
              }}
              disabled={disabled}
            >
              <SelectInput
                helperText="Primary account manager is required"
                label="Primary Account Manager *"
                optionText={saleOptionRenderer}
              />
            </ReferenceInput>
          </FormFieldWrapper>
        </div>

        {/* Secondary Account Manager - optional */}
        <div>
          <FormFieldWrapper name="secondary_sales_id">
            <ReferenceInput
              reference="sales"
              source="secondary_sales_id"
              sort={{ field: "last_name", order: "ASC" }}
              filter={{
                "disabled@neq": true,
                "user_id@not.is": null,
              }}
              disabled={disabled}
            >
              <SelectInput
                helperText={false}
                label="Secondary Account Manager"
                optionText={saleOptionRenderer}
              />
            </ReferenceInput>
          </FormFieldWrapper>
        </div>
      </FormSectionWithProgress>

      <CollapsibleSection title="Contact Methods">
        {/* Email - full width row (optional) */}
        <div>
          <FormFieldWrapper name="email">
            <EmailArrayField
              onEmailPaste={handleEmailPaste}
              onEmailBlur={handleEmailBlur}
              disabled={disabled}
            />
          </FormFieldWrapper>
        </div>

        {/* Phone - full width row */}
        <div>
          <FormFieldWrapper name="phone">
            <PhoneArrayField disabled={disabled} />
          </FormFieldWrapper>
        </div>
      </CollapsibleSection>

      <ContactAdditionalDetails disabled={disabled} />
    </div>
  );
};
